#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int C; scanf("%d", &C);
        int xorsum = 0;
        for (int i = 0; i < C; ++i) {
            int n, m; scanf("%d %d", &n, &m);
            int g = ( (n + m - 2) % 3 + 3 ) % 3; // Grundy value
            xorsum ^= g;
        }
        if (xorsum) printf("MasterChef\n");
        else printf("Football\n");
    }
    return 0;
}

