    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        C = int(next(it))
        xorsum = 0
        for _ in range(C):
            n = int(next(it)); m = int(next(it))
            g = ((n + m - 2) % 3 + 3) % 3
            xorsum ^= g
        out_lines.append('MasterChef' if xorsum else 'Football')
    sys.stdout.write('\n'.join(out_lines))

